import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getAIResponse = async (prompt: string, context?: string) => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: `You are NexusAssistant, the official AI guide for the NexusHub company intranet. 
        You help employees find information about company policies, IT support, and internal resources.
        Context about the company: 
        - Company Name: NexusHub
        - Values: Innovation, Transparency, People-First.
        - Common Tools: Slack, Jira, Confluence, Nexus-Expenses.
        If you don't know something specific about internal records, suggest they contact HR or IT via the sidebar tools.
        Keep responses concise, professional, and helpful.`,
        temperature: 0.7,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "I apologize, but I'm having trouble connecting to the network right now. Please try again or contact IT if the issue persists.";
  }
};

