      tool.description?.toLowerCase().includes(toolsSearch.toLowerCase())
    );
  }, [toolsSearch]);

  const toolCategories = useMemo(() => {
    const cats = Array.from(new Set(QUICK_TOOLS.map(t => t.category).filter(Boolean)));
    return ['全部', ...cats];
