import { GoogleGenAI } from "@google/genai";

export const getAIResponse = async (prompt: string, context?: string) => {
  // Initialize GoogleGenAI inside the function to use the most up-to-date API key from the environment.
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        systemInstruction: `你是 NexusAssistant，NexusHub 公司内网的官方 AI 指南。
        你的任务是帮助员工查找公司政策、IT 支持和内部资源。
        公司信息：
        - 公司名称：NexusHub
        - 核心价值观：创新、透明、以人为本。
        - 常用工具：Slack, Jira, Confluence, Nexus-Expenses。
        如果遇到你不了解的具体内部记录，建议用户通过导航栏工具联系人力资源部（HR）或 IT 部门。
        请使用中文回复，保持简洁、专业且富有帮助精神。`,
        temperature: 0.7,
      },
    });
    return response.text;
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "抱歉，目前连接网络出现问题。请稍后再试，或在问题持续时联系 IT 部门。";
  }
};

