            <div className="w-9 h-9 mesh-gradient rounded-xl flex items-center justify-center text-white font-black text-lg shadow-lg shadow-blue-500/30 group-hover:rotate-12 transition-transform duration-500">
              S
            </div>
            <span className="hidden lg:block font-black text-base text-slate-900 dark:text-white tracking-tighter">ShiKu Home</span>
          </div>

          {!isSearchVisible && (
            <div className="flex items-center space-x-1 lg:space-x-2 overflow-x-auto no-scrollbar">
              {menuItems.map((item) => (
                <button
                  key={item.id}
                  onClick={() => setView(item.id)}
                  className={`relative group flex items-center space-x-2 px-3 py-1.5 rounded-full transition-all duration-500 text-[10px] font-black uppercase tracking-tight whitespace-nowrap ${
                    currentView === item.id 
                      ? 'text-blue-600 dark:text-blue-400 bg-blue-50/50 dark:bg-blue-900/20' 
                      : 'text-slate-500 dark:text-slate-400 hover:text-slate-900 dark:hover:text-slate-100'
                  }`}
                >
                  {item.icon && React.isValidElement(item.icon) ? React.cloneElement(item.icon as React.ReactElement<any>, { size: 16 }) : item.icon}
                  <span className="hidden md:block">{item.label}</span>
                  {currentView === item.id && (
                    <div className="absolute -bottom-1 left-1/2 -translate-x-1/2 w-1 h-1 bg-blue-600 rounded-full"></div>
                  )}
                </button>
              ))}
            </div>
          )}

          {isSearchVisible && (
            <div className="flex-1 max-w-md animate-in slide-in-from-left-4 duration-300">
              <div className="relative">
                <Search size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                <input
                  ref={searchInputRef}
                  type="text"
                  value={globalSearch}
                  onChange={(e) => setGlobalSearch(e.target.value)}
                  placeholder="全局搜索..."
                  className="w-full bg-slate-100/50 dark:bg-slate-800/50 border-none rounded-full py-1.5 pl-10 pr-10 text-xs font-bold dark:text-white outline-none ring-2 ring-transparent focus:ring-blue-500/20 transition-all"
                />
                <button 
                  onClick={() => { setIsSearchVisible(false); setGlobalSearch(''); }}
                  className="absolute right-2 top-1/2 -translate-y-1/2 p-1 hover:bg-slate-200 dark:hover:bg-slate-700 rounded-full transition-colors"
                >
                  <X size={12} className="text-slate-500" />
                </button>
              </div>
            </div>
          )}
        </div>

        <div className="flex items-center space-x-2 shrink-0">
          {!isSearchVisible && (
            <button 
              onClick={() => setIsSearchVisible(true)}
              className="flex items-center justify-center w-9 h-9 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors text-slate-500"
            >
              <Search size={16} />
            </button>
          )}

          <button className="relative flex items-center justify-center w-9 h-9 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 transition-colors text-slate-500">
            <Bell size={16} />
            <span className="absolute top-2 right-2 w-2 h-2 bg-rose-500 rounded-full border-2 border-white dark:border-slate-900"></span>
          </button>

          <div className="relative" ref={dropdownRef}>
            <div 
              onClick={() => setIsProfileOpen(!isProfileOpen)}
              className="w-9 h-9 rounded-xl overflow-hidden ring-2 ring-white/50 dark:ring-slate-700 shadow-sm cursor-pointer hover:scale-110 transition-transform"
            >
               <img src="https://i.pravatar.cc/150?u=alex" alt="Alex" className="w-full h-full object-cover" />
            </div>

            {isProfileOpen && (
              <div className="absolute right-0 mt-3 w-48 mica rounded-3xl shadow-2xl overflow-hidden py-2 animate-in fade-in zoom-in-95 duration-200 border border-white/50 dark:border-slate-800">
                <button 
                  onClick={() => { setView(AppView.SETTINGS); setIsProfileOpen(false); }}
                  className="w-full flex items-center space-x-3 px-4 py-3 hover:bg-slate-50 dark:hover:bg-slate-800 text-slate-700 dark:text-slate-200 transition-colors text-xs font-bold uppercase tracking-widest"
                >
                  <Settings size={16} className="text-slate-400" />
                  <span>偏好设置</span>
                </button>
                <div className="h-px bg-slate-100 dark:bg-slate-800 mx-3 my-1"></div>
                <button 
                  className="w-full flex items-center space-x-3 px-4 py-3 hover:bg-rose-50 dark:hover:bg-rose-900/10 text-rose-600 transition-colors text-xs font-bold uppercase tracking-widest"
                >
                  <LogOut size={16} />
                  <span>退出系统</span>
                </button>
              </div>
            )}
          </div>
        </div>
      </nav>
    </div>
  );
};

