                      <span className="text-[8px] text-slate-400 font-bold">{news.date}</span>
                    </div>
                    <h3 className="text-lg font-black text-slate-900 dark:text-white leading-tight mb-1 group-hover:text-blue-600 transition-colors">
                      {news.title}
                    </h3>
                    <p className="text-[10px] text-slate-500 dark:text-slate-400 line-clamp-1">{news.summary}</p>
                  </div>
                </div>
              ))}
            </div>
          </section>
        </div>

        {/* Dynamic Sidebar */}
        <div className="lg:col-span-4 space-y-8">
          {/* Announcements Card */}
          <div className="mica rounded-[2rem] shadow-xl overflow-hidden border border-white/50">
            <div className="px-6 py-4 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white/30">
              <div className="flex items-center space-x-2">
                <div className="w-2 h-2 bg-rose-500 rounded-full animate-pulse"></div>
                <h3 className="font-black text-[10px] uppercase tracking-widest">实时公告</h3>
              </div>
              <BellRing size={14} className="text-slate-400" />
            </div>
            <div className="p-3 space-y-1">
              {MOCK_ANNOUNCEMENTS.slice(0, 3).map((item) => (
                <div key={item.id} className="group p-4 rounded-2xl hover:bg-white dark:hover:bg-slate-700/50 transition-all cursor-pointer">
                  <div className="flex justify-between items-center mb-1">
                     <span className={`text-[8px] font-black uppercase tracking-widest px-2 py-0.5 rounded-full ${getTagStyles(item.color)}`}>
                       {item.tag}
                     </span>
                     <span className="text-[8px] text-slate-400 font-bold">{item.time}</span>
                  </div>
                  <p className="text-[11px] font-bold text-slate-800 dark:text-slate-100 line-clamp-1">{item.title}</p>
                </div>
              ))}
            </div>
            <button 
              onClick={() => setIsAnnouncementsModalOpen(true)}
              className="w-full py-4 text-[9px] font-black uppercase tracking-widest text-slate-400 hover:text-blue-600 transition-colors border-t border-slate-100 dark:border-slate-800"
            >
              展开公告
            </button>
          </div>

          {/* Carousel Component */}
          <div className="relative group overflow-hidden mica rounded-[2rem] aspect-[16/10] shadow-xl border border-white/50">
            {CAROUSEL_ITEMS.map((item, idx) => (
              <a 
                key={item.id} 
                href={item.url}
                className={`absolute inset-0 transition-all duration-1000 ease-in-out ${idx === currentSlide ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-full'}`}
              >
                <img src={item.image} className="w-full h-full object-cover" alt={item.title} />
                <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent flex flex-col justify-end p-6">
                  <span className="text-[8px] font-black uppercase tracking-widest bg-blue-600 text-white px-2 py-0.5 rounded-full w-fit mb-2">
                    {item.badge}
                  </span>
                  <h3 className="text-white font-black text-base leading-tight tracking-tight drop-shadow-md">
                    {item.title}
                  </h3>
                </div>
              </a>
            ))}

            {/* Dots */}
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex space-x-1.5 z-20">
              {CAROUSEL_ITEMS.map((_, idx) => (
                <button 
                  key={idx}
                  onClick={() => setCurrentSlide(idx)}
                  className={`w-1.5 h-1.5 rounded-full transition-all duration-300 ${idx === currentSlide ? 'bg-white w-4' : 'bg-white/40'}`}
                />
              ))}
            </div>
          </div>

          <div className="mica rounded-[2rem] p-6 shadow-lg border border-white/50">
            <h3 className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-6 flex items-center">
              <div className="w-1.5 h-1.5 rounded-full bg-rose-500 mr-2"></div>
              职场关怀
            </h3>
            <div className="space-y-4">
              {[
                { name: 'Emily', img: 'emily', team: 'Design', status: 'Today' },
              ].map((b, i) => (
                <div key={i} className="flex items-center justify-between group">
                  <div className="flex items-center space-x-3">
                    <img src={`https://i.pravatar.cc/100?u=${b.img}`} className="w-10 h-10 rounded-xl" />
                    <div>
                      <p className="text-[11px] font-black text-slate-800 dark:text-slate-100">{b.name}</p>
                      <p className="text-[9px] text-slate-400 font-bold">{b.team}</p>
                    </div>
                  </div>
                  <span className="text-[8px] font-black uppercase tracking-widest text-rose-600">
                    {b.status}
                  </span>
                </div>
              ))}
            </div>
            <button className="w-full mt-6 py-3 bg-blue-600 text-white text-[9px] font-black uppercase tracking-widest rounded-2xl shadow-lg shadow-blue-500/20 hover:scale-105 transition-transform">
              发送祝愿
            </button>
          </div>
        </div>
      </div>

      {/* Announcements Modal */}
      {isAnnouncementsModalOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-6 animate-in fade-in duration-300">
          <div 
            className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm"
            onClick={() => setIsAnnouncementsModalOpen(false)}
          />
          <div className="mica w-full max-w-lg max-h-[80vh] rounded-organic shadow-2xl overflow-hidden flex flex-col animate-in zoom-in-95 slide-in-from-bottom-4 duration-500 border border-white/20">
            <div className="px-8 py-6 flex items-center justify-between border-b border-slate-100 dark:border-slate-800 bg-white/30 shrink-0">
              <div className="flex items-center space-x-3">
                <div className="w-10 h-10 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-blue-500/30">
                  <BellRing size={20} />
                </div>
                <div>
                  <h2 className="text-xl font-black text-slate-900 dark:text-white tracking-tighter uppercase">实时公告</h2>
                  <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest">ShiKu Home Bulletin Board</p>
                </div>
              </div>
              <button 
                onClick={() => setIsAnnouncementsModalOpen(false)}
                className="w-10 h-10 rounded-full hover:bg-slate-100 dark:hover:bg-slate-800 flex items-center justify-center text-slate-400 transition-colors"
              >
                <X size={20} />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 space-y-4 no-scrollbar">
              {MOCK_ANNOUNCEMENTS.map((item) => (
                <div key={item.id} className="mica p-6 rounded-[2rem] border border-white/50 shadow-sm hover:shadow-md transition-shadow">
                  <div className="flex justify-between items-start mb-4">
                    <div className="flex items-center space-x-3">
                      <span className={`text-[9px] font-black uppercase tracking-[0.2em] px-3 py-1 rounded-full ${getTagStyles(item.color)}`}>
                        {item.tag}
                      </span>
                      {item.isUrgent && (
                        <span className="flex items-center text-[9px] font-black text-rose-600 uppercase tracking-widest animate-pulse">
                          <AlertTriangle size={12} className="mr-1" />
                          紧急
                        </span>
                      )}
                    </div>
                    <div className="flex items-center space-x-1.5 text-slate-400">
                      <Timer size={12} />
                      <span className="text-[9px] font-bold">{item.time}</span>
                    </div>
                  </div>
                  <h3 className="text-lg font-black text-slate-900 dark:text-white leading-tight mb-2 tracking-tight">
                    {item.title}
                  </h3>
                  <p className="text-[11px] text-slate-500 dark:text-slate-400 leading-relaxed font-medium">
                    {item.content}
                  </p>
                </div>
              ))}
            </div>

            <div className="px-8 py-5 border-t border-slate-100 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-900/50 shrink-0 text-center">
              <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">
                您已阅读所有最新公告
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
